import React, { useState, useEffect } from 'react';
import axios from 'axios';

function ListaPacientes({ reloadKey, onEditar }) {
  const [pacientes, setPacientes] = useState([]);
  const [carregando, setCarregando] = useState(true);

  useEffect(() => {
    setCarregando(true);
    axios.get('/api/pacientes')
      .then(res => {
        setPacientes(res.data);
        setCarregando(false);
      })
      .catch(() => setCarregando(false));
  }, [reloadKey]);

  const handleDeletar = (id) => {
    if (window.confirm('Deletar este paciente?')) {
      axios.delete(`/api/pacientes/${id}`)
        .then(() => setPacientes(pacientes.filter(p => p.id !== id)));
    }
  };

  if (carregando) return <p>Carregando pacientes...</p>;
  if (pacientes.length === 0) return <p>Nenhum paciente cadastrado.</p>;

  return (
   <div className="mt-4">
  <h2 className="text-xl font-semibold mb-4 text-[#1d3557]">Lista de Pacientes</h2>
  {/* Cabeçalho de colunas */}
  <div className="flex px-5 pb-2 text-gray-500 font-bold text-sm">
    <div className="w-1/2">Nome</div>
    <div className="w-1/3">Telefone</div>
    <div className="w-1/6 text-right">Ações</div>
  </div>
  {/* Lista em cards */}
  <ul className="space-y-3">
    {pacientes.map((p) => (
      <li
        key={p.id}
        className="flex items-center bg-gray-50 rounded-xl px-5 py-3 shadow-sm hover:bg-gray-100 transition"
      >
        <div className="w-1/2 font-medium text-gray-800 truncate">{p.nome}</div>
        <div className="w-1/3 text-gray-500">{p.telefone}</div>
        <div className="w-1/6 flex justify-end space-x-2">
          <button
            onClick={() => onEditar(p)}
            className="px-4 py-1 rounded-lg bg-blue-100 text-blue-800 hover:bg-blue-200 font-semibold transition"
          >
            Editar
          </button>
          <button
            onClick={() => handleDeletar(p.id)}
            className="px-4 py-1 rounded-lg bg-red-100 text-red-700 hover:bg-red-200 font-semibold transition"
          >
            Deletar
          </button>
        </div>
      </li>
    ))}
  </ul>
</div>


  );
}

export default ListaPacientes;
